                    <th className="px-4 py-3 text-right">操作</th>
                 </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {snapshot.holdings.length === 0 && (
                   <tr><td colSpan={6} className="text-center py-8 text-slate-400">请上传截图或手动添加持仓</td></tr>
