export const fetchHighFreqSurveys = async (
  market: MarketType,
  apiKey: string
): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    作为资深投研分析师，利用 googleSearch 检索 ${market} 市场最近 1-2 周内【机构调研】数据。

    【核心目标】
    筛选并列出被机构调研“最频繁、次数最多、参与机构数量最集中”的公司排行榜。
    机构频繁调研往往预示着基本面的反转或重大题材的爆发。

    【要求】
    1. 挖掘出前 5-8 名高频标的。
    2. 指出为什么这些标的被频繁调研（背后的核心基本面逻辑）。
    3. 给出热度行业统计。

    必须输出 JSON 格式。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: hotlistSchema
    }
  });

  const text = response.text || "{}";
  const parsed = JSON.parse(text);

  return {
    content: text,
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    hotlistData: parsed,
    market
  };
};

export const fetchInstitutionalInsights = async (
  currentModel: ModelProvider,
  market: MarketType,
  settings: UserSettings
): Promise<AnalysisResult> => {
  const apiKey = settings.geminiKey || process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey: apiKey });

  const now = new Date();
  const dateStr = now.toLocaleDateString('zh-CN');

  const prompt = `
    [真实时间确认]: 现在是现实世界的 ${dateStr}。
    作为资深机构交易员，利用 googleSearch 深度分析 ${market} 市场当日最核心的机构大资金动向。

    【必填字段要求】:
    1. **当日龙虎榜 (Dragon Tiger List)**: 扫描今日龙虎榜中机构席位买卖净额最显著的前 5 只股票，记录代码、机构净买入额及逻辑。
    2. **当日主力资金流向 (Main Fund Flow)**: 汇总全市场主力净流入/流出总额，识别今日资金介入最深的行业。
    3. **详细信号解读**: 包含大宗交易折溢价及买卖盘差额 (Spread Trend) 的综述。
    4. **机构调研分布**: 汇总近期机构重点关注的行业热度。
    5. **券商核心观点**: 提取顶级内外资券商对今日盘面的总结。

    输出必须严格遵守 JSON 格式。
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: institutionalInsightsSchema
    }
  });

  const text = response.text || "{}";
  const parsed = JSON.parse(text);

  return {
    content: text,
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    institutionalData: parsed,
    market
  };
};

