                 </div>
              </footer>
            </div>
          </div>
        </main>

        <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} settings={userSettings} onSave={handleSaveSettings} />
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ModelProvider, AnalysisResult, UserSettings, MarketType } from '../types';
import { fetchInstitutionalInsights } from '../services/institutionService';
// Added Target to imports to fix line 270 error
import { Building2, Loader2, Search, Briefcase, Globe, Zap, Users, BarChart3, TrendingUp, AlertTriangle, ArrowRightCircle, Activity, LayoutGrid, Info, Flame, Trophy, Wallet, ArrowRight, Target } from 'lucide-react';
import { MARKET_OPTIONS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, CartesianGrid } from 'recharts';

interface InstitutionalMonitorProps {
  currentModel: ModelProvider;
  currentMarket: MarketType;
  settings: UserSettings;
  onOpenSettings?: () => void;
}

export const InstitutionalMonitor: React.FC<InstitutionalMonitorProps> = ({
  currentModel,
  currentMarket,
  settings,
  onOpenSettings
}) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    let interval: any;
    if (loading) {
      setElapsed(0);
      interval = setInterval(() => setElapsed(prev => prev + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleAnalyze = async () => {
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      const data = await fetchInstitutionalInsights(currentModel, currentMarket, settings);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "获取机构调研数据失败");
    } finally {
      setLoading(false);
    }
  };

  const institutionalData = result?.institutionalData;

  return (
    <div className="space-y-6 animate-fade-in max-w-7xl mx-auto pb-20">
      {/* Header */}
