              onClick={handleAnalyze}
              disabled={loading}
              className="flex items-center gap-3 px-8 py-4 bg-slate-900 hover:bg-slate-800 text-white rounded-2xl font-black transition-all shadow-2xl active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed whitespace-nowrap text-lg"
            >
              {loading ? (
                 <>
                   <Loader2 className="w-6 h-6 animate-spin" />
                   <span>正在回溯主力监控点 ({elapsed}s)...</span>
