interface DailyCapitalReportProps {
  currentMarket: MarketType;
  currentModel: ModelProvider;
  settings: UserSettings;
  savedStockResult: AnalysisResult | null;
  onStockResultUpdate: (result: AnalysisResult | null) => void;
  savedStockQuery: string;
  onStockQueryUpdate: (query: string) => void;
