        else setPhase("正在为您筛选并格式化高胜率标的...");
      }
    }
  }, [elapsed, loading, mode]);

  const handleMine = async () => {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      let data: AnalysisResult;
      if (mode === 'survey') {
         data = await fetchHighFreqSurveys(currentMarket, "");
      } else {
         data = await fetchOpportunityMining(currentModel, currentMarket, settings, inputData, mode === 'chain' ? 'chain' : 'foresight');
      }
      setResult(data);
    } catch (err: any) {
      console.error("Discovery Error:", err);
      setError(err.message || "分析中断，请检查网络。");
    } finally {
      setLoading(false);
    }
  };

  const handleNavigateToStock = (code: string, name: string) => {
    navigate(`/stock?q=${encodeURIComponent(code + " " + name)}`);
  };

  return (
    <div className="space-y-8 animate-fade-in max-w-7xl mx-auto pb-24">
      {/* 1. Header Card - 专业投研风格 */}
      <div className="bg-slate-950 rounded-[2.5rem] shadow-2xl p-8 md:p-12 relative overflow-hidden text-white">
        <div className="absolute right-0 top-0 opacity-10 pointer-events-none">
           <Building2 className="w-96 h-96 -mr-20 -mt-20" />
        </div>

        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 mb-12">
             <div className="max-w-2xl">
                <div className="flex items-center gap-3 mb-4">
                   <div className="p-2.5 bg-indigo-500 rounded-xl">
                      <Sparkles className="w-6 h-6 text-white" />
                   </div>
                   <span className="text-xs font-black uppercase tracking-[0.4em] text-indigo-300">Alpha Discovery Engine</span>
                </div>
                <h2 className="text-4xl font-black tracking-tight mb-4">投研掘金内参</h2>
                <p className="text-slate-400 text-lg font-medium leading-relaxed">
                   深度融合**产业链博弈逻辑**与**机构高频调研信号**。AI 实时穿透海量研报与纪要，挖掘具备“预期差”的潜伏机会。
                </p>
             </div>

             <div className="flex bg-white/10 p-1.5 rounded-2xl backdrop-blur-md border border-white/10">
                <button 
                  onClick={() => setMode('chain')}
                  className={`px-6 py-3 text-sm font-black rounded-xl transition-all ${mode === 'chain' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 hover:text-slate-200'}`}
