/**
 * Analyzes stock detail with an image provided
 */
export const fetchStockDetailWithImage = async (selectedImage: string, query: string, market: MarketType, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: selectedImage,
    },
  };
  const textPart = {
    text: `
      请对 ${market} 的股票 "${query}" 进行深度量化分析。
      我提供了一张该标的的 K 线走势或量价截图。请优先结合图中展现的形态（如底背离、放量突破、MACD交叉等）进行诊断。
      输出必须包含基础数据、关键价位、量化评级、操作建议和核心逻辑。
    `
  };

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: { parts: [imagePart, textPart] },
    config: { tools: [{ googleSearch: {} }] }
  });

  return {
    content: response.text || "",
    groundingSource: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      uri: chunk.web?.uri || "",
      title: chunk.web?.title || "网页来源"
    })),
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL
  };
};

/**
 * Parses brokerage screenshot into structured holding data
 */
export const parseBrokerageScreenshot = async (base64String: string, apiKey: string): Promise<HoldingsSnapshot> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const imagePart = {
    inlineData: {
      mimeType: 'image/png',
      data: base64String,
    },
  };
  const textPart = {
    text: "请识别这张券商持仓截图中的所有资产信息。输出为 JSON 格式，包含 totalAssets, date (YYYY-MM-DD), 和 holdings 列表。"
  };

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: { parts: [imagePart, textPart] },
    config: {
      responseMimeType: "application/json",
      responseSchema: holdingsSnapshotSchema
    }
  });

  return robustParse(response.text || "{}") as HoldingsSnapshot;
};

