    【核心审计任务】：
    1. **跨年实力审计 (Alpha vs Beta)**：利用 googleSearch 检索并对比 12 月至今 ${market} 市场的表现。特别是上证指数 7 连阳期间，全市场中位数涨幅是多少？用户的盈利是超越了普涨，还是仅仅跟随？
    2. **执行力验证**：用户自称 12 月中旬开始坚持复盘且执行力 80 分。请审计这 80 分在市场 12 月底的调整中起到了多大的防守作用。
    3. **逻辑兑现分析**：针对用户的盈利品种（如国机精工、航天电子等），分析其盈利是因为“新质生产力”逻辑兑现，还是年底资金脉冲的偶然性。
    4. **1月行情前瞻**：给出 1 月份的应对策略（防守切换还是主线潜伏）。

    历史数据：
    ${JSON.stringify(historyData, null, 2)}

    必须输出严格的 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: periodicReviewSchema
    }
  });

  const parsed = robustParse(response.text || "{}");
  return {
    content: response.text || "",
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL,
    isStructured: true,
    periodicData: parsed,
    market
  };
};

export const fetchGeminiAnalysis = async (prompt: string, isComplex: boolean, apiKey: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = isComplex ? GEMINI_MODEL_COMPLEX : GEMINI_MODEL_PRIMARY;
  const response = await ai.models.generateContent({
    model: model,
    contents: prompt,
    config: { tools: [{ googleSearch: {} }] }
  });
  return {
    content: response.text || "",
    groundingSource: response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      uri: chunk.web?.uri || "",
      title: chunk.web?.title || "网页来源"
    })),
    timestamp: Date.now(),
    modelUsed: ModelProvider.GEMINI_INTL
  };
};

