    holdings: j.snapshot?.holdings?.map((h: any) => ({ name: h.name, profit: h.profit, profitRate: h.profitRate, cost: h.costPrice, price: h.currentPrice })),
    totalAssets: j.snapshot?.totalAssets
  }));

  const prompt = `
    作为资深基金经理，基于以下历史持仓记录进行【${label}】的阶段性复盘。

    【核心审计任务】：
    1. **成本剥离审计**：
       - **特别说明**：如果某个标的（如“国机精工”）的成本价显示为 0 或负数，这【绝非】错误，而是用户通过“T+0”或多次高抛低吸成功将原始投入全部收回。
       - 此时请将其定性为“高阶实战成功的标志”或“零成本持仓”，并分析其“利润裸奔”状态下的持仓心态优势。禁止将其视为录入错误。

    2. **建议与方法论建议**：
       - 对于诊断中发现的每一项不足或问题，你必须提供至少一条具体的、基于量化或实战的【改进建议与方法】（例如：具体的指标阈值、情绪控制技巧、或调仓纪律）。

    3. **跨年实力审计 (Alpha vs Beta)**：利用 googleSearch 检索并对比 12 月至今 ${market} 市场的表现。

    历史数据：
    ${JSON.stringify(historyData, null, 2)}

    必须输出严格的 JSON。
  `;

  const response = await ai.models.generateContent({
    model: GEMINI_MODEL_PRIMARY,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: periodicReviewSchema
