                 </h4>
                 {data.execution.good_behaviors.map((b, i) => (
                    <div key={i} className="bg-emerald-50 text-emerald-800 p-3 rounded-xl text-xs font-bold">{b}</div>
                 ))}
              </div>
              <div className="space-y-3">
                 <h4 className="text-[10px] font-black text-rose-600 uppercase tracking-widest flex items-center gap-2">
                    <XCircle className="w-4 h-4" /> 行为扣分
                 </h4>
                 {data.execution.bad_behaviors.map((b, i) => (
                    <div key={i} className="bg-rose-50 text-rose-800 p-3 rounded-xl text-xs font-bold">{b}</div>
                 ))}
              </div>
           </div>
        </div>
      </div>
    );
  };

  const deleteJournalEntry = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("确定删除？")) setJournal(prev => prev.filter(j => j.id !== id));
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 p-8">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-8">
           <div>
              <h2 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                 <Sparkles className="w-7 h-7 text-indigo-600" />
                 持仓实战复盘与能力审计
              </h2>
              <p className="text-slate-500 text-sm mt-1 font-medium">连续复盘是进阶交易者的唯一捷径。目前正处于 12月跨年转折审计期。</p>
           </div>
           <div className="flex gap-3">
              <button onClick={() => setIsHistoryOpen(!isHistoryOpen)} className="flex items-center gap-2 px-4 py-2 text-sm font-black text-slate-600 bg-slate-50 hover:bg-slate-100 rounded-xl border border-slate-200"><History className="w-4 h-4" /> 历史日志</button>
              <input type="file" accept="image/*" ref={fileInputRef} className="hidden" onChange={handleImageUpload} />
              <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black shadow-lg transition-all"><Camera className="w-5 h-5" /> 同步持仓</button>
           </div>
        </div>

        {isHistoryOpen && (
          <div className="mb-6 p-4 bg-slate-50 rounded-3xl border border-slate-200 animate-slide-down">
             <h3 className="font-black text-slate-700 mb-4 px-4">历史审计日志</h3>
             <div className="space-y-2">
                {journal.map(j => (
                  <div key={j.id} onClick={() => { setSnapshot(j.snapshot); setAnalysisResult(j.analysis); setIsHistoryOpen(false); }} className="p-4 bg-white rounded-2xl border border-slate-200 hover:border-indigo-400 cursor-pointer flex justify-between items-center group">
                    <div className="text-sm font-bold text-slate-800">{new Date(j.timestamp).toLocaleString()}</div>
                    <button onClick={(e) => deleteJournalEntry(j.id, e)} className="p-2 text-slate-300 hover:text-rose-600"><Trash2 className="w-4 h-4" /></button>
                  </div>
                ))}
             </div>
          </div>
        )}

        <div className="overflow-x-auto rounded-3xl border border-slate-200 mb-8">
           <table className="w-full text-sm text-left">
              <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest">
                 <tr><th className="px-6 py-4">标的信息</th><th className="px-6 py-4">持仓详情</th><th className="px-6 py-4">实时盈亏</th><th className="px-6 py-4 text-right">操作</th></tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                 {snapshot.holdings.map((h, i) => (
                    <tr key={i} className="hover:bg-slate-50/50">
                       <td className="px-6 py-4"><div className="font-black text-slate-800 text-lg">{h.name}</div><div className="text-xs font-mono text-slate-400">{h.code}</div></td>
                       <td className="px-6 py-4"><div className="text-slate-600 font-bold">{h.volume} 股 / 成本 {h.costPrice}</div><div className="text-xs text-slate-400 mt-0.5">现价 {h.currentPrice}</div></td>
                       <td className="px-6 py-4"><div className={`font-black text-lg ${h.profit >= 0 ? 'text-rose-500' : 'text-emerald-500'}`}>{h.profit >= 0 ? '+' : ''}{h.profit}</div><div className={`text-xs font-bold ${h.profit >= 0 ? 'text-rose-400' : 'text-emerald-400'}`}>{h.profitRate}</div></td>
                       <td className="px-6 py-4 text-right"><button className="p-2 text-slate-300 hover:text-indigo-600"><Edit2 className="w-4 h-4"/></button></td>
                    </tr>
                 ))}
              </tbody>
           </table>
        </div>

        <div className="flex justify-end gap-4">
           <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
              <button onClick={() => handlePeriodicReview('week')} className="px-4 py-2 text-xs font-black text-slate-500 hover:bg-white hover:text-indigo-600 rounded-xl transition-all">近一周复盘</button>
              <button onClick={() => handlePeriodicReview('month')} className="px-4 py-2 text-xs font-black text-slate-500 hover:bg-white hover:text-indigo-600 rounded-xl transition-all">近一月审计</button>
           </div>
           <button onClick={handleAnalyze} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black shadow-xl hover:bg-slate-800 transition-all flex items-center gap-2"><TrendingUp className="w-5 h-5" /> 开始 AI 实战复盘</button>
        </div>
      </div>

      {(analysisResult || periodicResult) && (
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden animate-slide-up">
           <div className="bg-slate-50 px-8 py-5 border-b border-slate-200 flex justify-between items-center">
              <div className="flex gap-6">
                <button onClick={() => setActiveTab('report')} className={`text-sm font-black transition-all ${activeTab === 'report' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>日度诊断</button>
                <button onClick={() => setActiveTab('periodic')} className={`text-sm font-black transition-all ${activeTab === 'periodic' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}>能力审计 (Alpha Audit)</button>
              </div>
              <button onClick={saveToJournal} className="flex items-center gap-2 px-4 py-2 text-xs font-black bg-white border border-slate-200 rounded-xl shadow-sm hover:bg-slate-50"><Save className="w-4 h-4"/> 存档日志</button>
           </div>
           <div className="min-h-[500px]">
             {activeTab === 'report' && analysisResult ? (
                <div className="p-8 prose prose-slate max-w-none" dangerouslySetInnerHTML={{ __html: analysisResult.content.replace(/\n/g, '<br/>') }}></div>
             ) : activeTab === 'periodic' && periodicResult?.periodicData ? renderPeriodicDashboard(periodicResult.periodicData) : (
                <div className="p-20 text-center text-slate-300 font-black text-xl italic uppercase tracking-widest">请选择复盘周期以调取 Alpha 审计数据</div>
             )}
           </div>
        </div>
      )}
    </div>
  );
};
